mapper.sql:
WHERE aul.feature_type IN ('JOB_ANALYSIS', 'COMPANY_RESEARCH', 'JOB_POSTING_OCR')

    AND aul.feature_type = #{criteria.featureType}


    AND aul.status = #{criteria.status}


    AND (
        u.email LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR ac.company_name LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR ac.job_title LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR aul.feature_type LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR aul.status LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR aul.model LIKE CONCAT('%', #{criteria.keyword}, '%')
        OR aul.error_message LIKE CONCAT('%', #{criteria.keyword}, '%')
    )


    AND aul.application_case_id = #{criteria.applicationCaseId}


    AND aul.user_id = #{criteria.userId}


    AND aul.model = #{criteria.model}


    AND aul.created_at >= #{criteria.createdFrom}


    AND aul.created_at < DATE_ADD(#{criteria.createdTo}, INTERVAL 1 DAY)

mapper.select:

WHERE aul.feature_type IN ('JOB_ANALYSIS', 'COMPANY_RESEARCH', 'JOB_POSTING_OCR')
  AND aul.application_case_id = #{applicationCaseId}
ORDER BY aul.created_at DESC, aul.id DESC
LIMIT #{limit}
